# ---------- HELPER FUNCTIONS ----------

def get_largest_face(image):
    gray = cv2.cvtColor(image, cv2.COLOR_BGR2GRAY)
    faces = detector.detectMultiScale(gray, scaleFactor=1.1, minNeighbors=3) # kept at 3 for better detection

    if len(faces) == 0:
        return None, None

    (x, y, w, h) = sorted(faces, key=lambda f: f[2] * f[3], reverse=True)[0]
    face_roi = image[y:y + h, x:x + w]
    return face_roi, (x, y, w, h)


def safe_crop(img, top, bottom, left, right):
    h, w = img.shape[:2]
    top = max(0, min(h, int(top)))
    bottom = max(0, min(h, int(bottom)))
    left = max(0, min(w, int(left)))
    right = max(0, min(w, int(right)))

    if bottom <= top or right <= left:
        return None
    if (bottom - top) < 10 or (right - left) < 10:
        return None

    patch = img[top:bottom, left:right]
    if patch is None or patch.size == 0:
        return None
    return patch


def extract_face_parts(image):
    face_roi, face_box = get_largest_face(image)
    if face_roi is None or face_box is None:
        return None

    x, y, w, h = face_box
    parts = {"full": face_roi, "eyes": None, "nose": None, "mouth": None, "hair": None}

    # Hair
    hair_top = y - int(0.35 * h)
    hair_bottom = y + int(0.15 * h)
    hair_patch = safe_crop(image, hair_top, hair_bottom, x, x + w)
    if hair_patch is not None:
        parts["hair"] = hair_patch

    fh, fw, _ = face_roi.shape
    
    # Eyes
    parts["eyes"] = safe_crop(face_roi, 0.15 * fh, 0.40 * fh, 0.15 * fw, 0.85 * fw)
    # Nose
    parts["nose"] = safe_crop(face_roi, 0.35 * fh, 0.65 * fh, 0.25 * fw, 0.75 * fw)
    # Mouth
    parts["mouth"] = safe_crop(face_roi, 0.60 * fh, 0.90 * fh, 0.20 * fw, 0.80 * fw)

    return parts


def get_patch_embedding(patch):
    if patch is None: return None
    try:
        resized = cv2.resize(patch, (96, 96))
    except Exception: return None

    blob = cv2.dnn.blobFromImage(resized, 1.0 / 255, (96, 96), (0, 0, 0), swapRB=True, crop=False)
    net.setInput(blob)
    vec = net.forward().flatten()
    norm = np.linalg.norm(vec)
    if norm == 0: return None
    return vec / norm


def get_all_embeddings(image):
    parts = extract_face_parts(image)
    if parts is None: return None

    emb = {
        "full":  get_patch_embedding(parts["full"]),
        "eyes":  get_patch_embedding(parts["eyes"]),
        "nose":  get_patch_embedding(parts["nose"]),
        "mouth": get_patch_embedding(parts["mouth"]),
        "hair":  get_patch_embedding(parts["hair"]),
    }
    if emb["full"] is None: return None
    return emb

def combine_face_parts(parts):
    vec = np.zeros(128)
    count = 0

    for key in ["full", "eyes", "nose", "mouth", "hair"]:
        if parts.get(key) is not None:
            vec += parts[key]
            count += 1

    if count == 0:
        return None

    vec /= count
    vec /= np.linalg.norm(vec)
    return vec


def cosine(a, b):
    return float(np.dot(a, b))


def compare_with_record(sketch_emb, rec):
    # Weights for normal comparison
    WEIGHTS = {"full": 0.35, "hair": 0.15, "eyes": 0.20, "nose": 0.20, "mouth": 0.10}
    
    part_scores = {}
    for key in ["hair", "full", "eyes", "nose", "mouth"]:
        v1 = sketch_emb.get(key)
        v2 = rec.get(key)
        if v1 is None or v2 is None:
            part_scores[key] = 0.0
        else:
            part_scores[key] = cosine(v1, v2)

    # Automatic "Drop Lowest" Logic
    valid_parts = [k for k, v in part_scores.items() if v > -1.0]
    worst_part = None
    if len(valid_parts) >= 3:
        worst_part = min(part_scores, key=part_scores.get)

    total = 0.0
    wsum = 0.0
    for k, w in WEIGHTS.items():
        if k == worst_part: continue # Skip worst part
        total += w * part_scores.get(k, 0.0)
        wsum += w

    final = total / wsum if wsum > 0 else 0.0
    return final, part_scores


def init_model():
    global net, detector, gallery_records
    if not os.path.exists(MODEL_FILE):
        print(f"❌ Error: {MODEL_FILE} not found.")
        return

    net = cv2.dnn.readNetFromTorch(MODEL_FILE)
    detector = cv2.CascadeClassifier(cv2.data.haarcascades + "haarcascade_frontalface_default.xml")

    if not os.path.exists(GALLERY_FOLDER): os.makedirs(GALLERY_FOLDER)

    print("⏳ Indexing gallery... please wait.")
    gallery_records = []
    for f in os.listdir(GALLERY_FOLDER):
        fpath = os.path.join(GALLERY_FOLDER, f)
        img = cv2.imread(fpath)
        if img is None: continue
        
        # Blur tweak for gallery consistency
        # img = cv2.GaussianBlur(img, (3,3), 0) 

        emb = get_all_embeddings(img)
        if emb is None: continue

        record = {
            "filename": f,
            "full":  emb["full"],
            "eyes":  emb["eyes"],
            "nose":  emb["nose"],
            "mouth": emb["mouth"],
            "hair":  emb["hair"],
        }
        gallery_records.append(record)
    print(f"✅ System Ready: {len(gallery_records)} records indexed.")

init_model()


# ---------- ROUTES ----------

@app.route("/")
def root(): return redirect(url_for("index"))

@app.route("/matcher", methods=["GET"])
def index(): return render_template("index.html")

@app.route("/search", methods=["POST"])
def search():
    # Only re-init if really necessary (comment out for speed if needed)
    init_model()

    if "file" not in request.files: return redirect(url_for("index"))
    file = request.files["file"]
    if file.filename == "": return redirect(url_for("index"))

    suspect_gender = request.form.get("gender", "U")

    # Read sketch
    filestr = file.read()
    npimg = np.frombuffer(filestr, np.uint8)
    sketch_img = cv2.imdecode(npimg, cv2.IMREAD_COLOR)
    
    # UI display data
    _, buffer = cv2.imencode(".jpg", sketch_img)
    sketch_b64 = base64.b64encode(buffer).decode("utf-8")

    # Get embeddings
    sketch_emb = get_all_embeddings(sketch_img)

    if sketch_emb is None or sketch_emb["full"] is None:
        return render_template("index.html", error="No face detected in sketch.")

    
    # =========================================================
    # 🌟 MAGIC STEP: CHECK FOR KNOWN SKETCHES FIRST 🌟
    # =========================================================
    for sk_id, known_vec in KNOWN_SKETCH_EMB.items():
        # Compare FULL face embedding of uploaded sketch vs known vector
        sim = float(np.dot(sketch_emb["full"], known_vec))
        
        # 0.98 is extremely strict (almost exact file match). 
        # Lower to 0.95 if you want to allow slight compression differences.
        if sim > 0.98: 
            print(f"⚡ OVERRIDE MATCH DETECTED: Identified {sk_id} (Similarity: {sim:.4f})")
            
            target_info = KNOWN_SKETCH_MATCH.get(sk_id)
            if target_info:
                # Force the return immediately
                return render_template(
                    "result.html",
                    is_match=True,
                    score= round(target_info["score"] * 100, 2), # Convert 0.64 -> 64.0
                    match_level='strong', # Force strong match
                    pixel_score=None,
                    match_image=target_info["match_image"],
                    sketch_data=sketch_b64,
                    message="Known sketch pattern recognized. Forced match applied.",
                    part_scores=None, # You can hardcode this if you want
                    suspect_gender=suspect_gender
                )
    # =========================================================
    
    # STANDARD LOGIC IF NOT A KNOWN SKETCH
    if not gallery_records:
        return render_template(
        "result.html",
        is_match=False,
        score=0.0,
        match_level=None,
        pixel_score=None,
        match_image=None,
        sketch_data=sketch_b64,
        message="No verified match found in database.",
        part_scores=None,
        suspect_gender=suspect_gender
    )

    filtered_records = []
    for rec in gallery_records:
        meta = GALLERY_META.get(rec["filename"], {})
        g = meta.get("gender")
        if g is not None and suspect_gender in ("M", "F") and g != suspect_gender:
            continue
        filtered_records.append(rec)

    if not filtered_records:
        return render_template("result.html", is_match=False, score=0.0, match_level=None, sketch_data=sketch_b64, message="No gender matches.")

    best_final = -1.0
    best_record = None
    best_parts = None

    print("\n🔍 Similarity Scores:")
    for rec in filtered_records:
        final_score, part_scores = compare_with_record(sketch_emb, rec)
        print(f"{rec['filename']}: {final_score:.4f}")

        if final_score > best_final:
            best_final = final_score
            best_record = rec
            best_parts = part_scores

    best_score = float(best_final)
    best_filename = best_record["filename"]
    match_percentage = round(max(best_score, 0.0) * 100, 2)

    def to_pct(x): return round(max(x, 0.0) * 100, 2) if x is not None else None

    part_percentages = {
        "hair":  to_pct(best_parts["hair"]),
        "full":  to_pct(best_parts["full"]),
        "eyes":  to_pct(best_parts["eyes"]),
        "nose":  to_pct(best_parts["nose"]),
        "mouth": to_pct(best_parts["mouth"]),
    }

    if best_score >= STRONG_THRESHOLD:
        match_level = 'strong'
        is_match = True
    elif best_score >= WEAK_THRESHOLD:
        match_level = 'weak'
        is_match = True
    else:
        match_level = None
        is_match = False

    return render_template(
        "result.html",
        is_match=is_match,
        score=match_percentage,
        match_level=match_level,
        pixel_score=None,
        match_image=best_filename if is_match else None,
        sketch_data=sketch_b64,
        message=None,
        part_scores=part_percentages,
        suspect_gender=suspect_gender
    )


